import React from 'react';
import { LayoutDashboard, TrendingUp, Users, ArrowUpRight, Clock, CheckCircle } from 'lucide-react';

export default function Dashboard() {
  const stats = [
    { label: 'Total Barters', value: '48', icon: <TrendingUp size={20}/> },
    { label: 'Active Requests', value: '12', icon: <Clock size={20}/> },
    { label: 'Rating', value: '4.9', icon: <CheckCircle size={20}/> },
  ];

  return (
    <div className="p-10 max-w-7xl mx-auto space-y-10">
      {/* ORIGINAL HEADER */}
      <div className="flex justify-between items-end">
        <div>
          <h1 className="text-4xl font-black text-slate-800 tracking-tighter uppercase italic">Welcome Back, Gouri</h1>
          <p className="text-slate-400 font-bold text-[10px] tracking-[0.2em] mt-1 uppercase">Your trading activity at a glance</p>
        </div>
        <div className="p-4 bg-teal-50 text-teal-600 rounded-3xl">
          <LayoutDashboard size={24} />
        </div>
      </div>

      {/* ORIGINAL STATS GRID */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {stats.map((stat, i) => (
          <div key={i} className="bg-white p-8 rounded-[40px] border border-slate-100 shadow-sm flex items-center justify-between transition-transform hover:scale-[1.02]">
            <div>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{stat.label}</p>
              <h3 className="text-3xl font-black text-slate-800">{stat.value}</h3>
            </div>
            <div className="p-5 bg-teal-50 text-teal-600 rounded-2xl">
              {stat.icon}
            </div>
          </div>
        ))}
      </div>

      {/* ORIGINAL RECENT ACTIVITY LIST */}
      <div className="bg-white rounded-[40px] p-10 border border-slate-100 shadow-sm">
        <h3 className="text-xl font-black text-slate-800 mb-8 flex items-center gap-3">
          <Clock className="text-teal-600" /> Recent Activity
        </h3>
        <div className="space-y-6">
          {[
            { item: 'Graphic Design', user: 'Rahul K.', status: 'Completed', date: 'Oct 12' },
            { item: 'JavaScript Mentoring', user: 'Suresh V.', status: 'Pending', date: 'Oct 14' },
            { item: 'UI/UX Review', user: 'Aditi M.', status: 'Accepted', date: 'Oct 15' },
          ].map((activity, i) => (
            <div key={i} className="flex items-center justify-between py-4 border-b border-slate-50 last:border-none">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-slate-50 rounded-2xl flex items-center justify-center font-black text-teal-600 text-xs">
                  {activity.item.substring(0, 2).toUpperCase()}
                </div>
                <div>
                  <p className="font-black text-slate-800">{activity.item}</p>
                  <p className="text-xs font-bold text-slate-400">With {activity.user}</p>
                </div>
              </div>
              <div className="text-right">
                <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest ${
                  activity.status === 'Completed' ? 'bg-teal-600 text-white' : 'bg-slate-100 text-slate-400'
                }`}>
                  {activity.status}
                </span>
                <p className="text-[9px] font-black text-slate-300 mt-2 uppercase">{activity.date}</p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
